TITLE = '新築 vs 中古住宅 比較診断｜予算・条件から最適な住宅を提案'
DESCRIPTION = '予算・条件から新築と中古の総コストを比較し最適な選択を提案。8つの質問でリフォームコスト・ローン・立地など総合的に比較する無料診断ツール。'
JS_CODE = 'const answers = {};\n    const totalQ = 8;\n\n    document.querySelectorAll(\'.quiz-btn\').forEach(btn => {\n      btn.addEventListener(\'click\', function() {\n        const q = parseInt(this.dataset.q);\n        const v = this.dataset.v;\n        answers[q] = v;\n        document.querySelectorAll(`[data-q="${q}"]`).forEach(b => b.classList.remove(\'border-blue-500\',\'bg-blue-100\'));\n        this.classList.add(\'border-blue-500\',\'bg-blue-100\');\n        setTimeout(() => {\n          if (q < totalQ) {\n            document.getElementById(`q${q}`).classList.add(\'hidden\');\n            document.getElementById(`q${q+1}`).classList.remove(\'hidden\');\n            document.getElementById(\'progress-bar\').style.width = (q/totalQ*100)+\'%\';\n            document.getElementById(\'progress-text\').textContent = `質問 ${q+1} / ${totalQ}`;\n          } else { showResult(); }\n        }, 300);\n      });\n    });\n\n    function showResult() {\n      document.getElementById(\'quiz-section\').classList.add(\'hidden\');\n      document.getElementById(\'result-section\').classList.remove(\'hidden\');\n\n      const budget = answers[1];\n      const area = answers[2];\n      const reform = answers[4];\n      const timing = answers[5];\n      const priority = answers[7];\n      const period = answers[8];\n\n      let newScore = 0, usedScore = 0;\n      const newPros = [], usedPros = [];\n      const newCons = [], usedCons = [];\n\n      // Budget\n      if (budget === \'2000\') { usedScore += 3; usedPros.push(\'予算内で広めの物件が見つかりやすい\'); newCons.push(\'新築は都市部では予算内が難しい\'); }\n      else if (budget === \'3500\') { usedScore += 1; newScore += 1; }\n      else { newScore += 2; newPros.push(\'予算的に新築も選択肢に\'); }\n\n      // Area\n      if (area === \'urban\') { usedScore += 2; usedPros.push(\'都市部・駅近の中古物件はコスパ最高\'); newCons.push(\'都市部新築は価格が高騰\'); }\n      else if (area === \'rural\') { newScore += 1; }\n\n      // Reform\n      if (reform === \'ok\') { usedScore += 3; usedPros.push(\'フルリノベで自分好みの空間を実現\'); }\n      else if (reform === \'new-only\') { newScore += 3; newPros.push(\'新築なら設備・デザインが最新・保証充実\'); }\n      else if (reform === \'no\') { newScore += 1; }\n\n      // Timing\n      if (timing === \'asap\') { usedScore += 2; usedPros.push(\'中古は即入居可能な物件が多い\'); newCons.push(\'新築（建売除く）は竣工まで時間がかかる\'); }\n      else if (timing === \'flexible\') { newScore += 1; }\n\n      // Priority\n      if (priority === \'size\') { usedScore += 2; usedPros.push(\'同予算で広い物件を選びやすい\'); }\n      else if (priority === \'location\') { usedScore += 1; }\n      else if (priority === \'quality\') { newScore += 2; newPros.push(\'最新設備・断熱・耐震基準で安心\'); }\n      else if (priority === \'cost\') { usedScore += 2; usedPros.push(\'総コストは中古が圧倒的に有利なことが多い\'); }\n\n      // Period\n      if (period === \'short\') { usedScore += 1; usedPros.push(\'転売時の価格下落が新築より少ない場合も\'); }\n      else if (period === \'forever\') { newScore += 1; newPros.push(\'長期居住なら新築の耐久性・保証が有利\'); }\n\n      const recommendation = newScore > usedScore ? \'新築\' : usedScore > newScore ? \'中古（リノベ）\' : \'甲乙つけがたい（物件次第）\';\n      const recColor = newScore > usedScore ? \'bg-green-50 border-green-400 text-green-700\' : usedScore > newScore ? \'bg-blue-50 border-blue-400 text-blue-700\' : \'bg-yellow-50 border-yellow-400 text-yellow-700\';\n\n      // Cost comparison\n      const budgetMap = { \'2000\': 2000, \'3500\': 3000, \'5000\': 4500, \'over5000\': 6000 };\n      const budgetVal = budgetMap[budget] || 3000;\n      const newCost = budgetVal;\n      const usedCost = Math.round(budgetVal * 0.65);\n      const reformCost = Math.round(budgetVal * 0.15);\n      const usedTotal = usedCost + reformCost;\n\n      let html = `\n        <div class="border-2 ${recColor} rounded-xl p-5 mb-4 text-center">\n          <div class="text-3xl mb-1">🏡</div>\n          <h3 class="text-xl font-bold">あなたには「${recommendation}」がおすすめ</h3>\n        </div>\n\n        <div class="grid grid-cols-2 gap-4 mb-4">\n          <div class="bg-green-50 border border-green-300 rounded-xl p-4">\n            <p class="text-center font-bold text-green-700 mb-2">🏗️ 新築</p>\n            <p class="text-center text-2xl font-bold text-gray-800">${newCost}万円</p>\n '
